import{_ as a,o as e,c as d,ai as r}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第八课：常用估值指标","description":"","frontmatter":{},"headers":[],"relativePath":"guide/08-valuation-metrics.md","filePath":"guide/08-valuation-metrics.md","lastUpdated":0}'),i={name:"guide/08-valuation-metrics.md"};function s(l,t,h,n,o,b){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="第八课-常用估值指标" tabindex="-1">第八课：常用估值指标 <a class="header-anchor" href="#第八课-常用估值指标" aria-label="Permalink to “第八课：常用估值指标”">​</a></h1><p>知道公司盈利了，还要判断&quot;贵不贵&quot;。估值就是给股票称重。</p><h2 id="一、市盈率-pe" tabindex="-1">一、市盈率（PE） <a class="header-anchor" href="#一、市盈率-pe" aria-label="Permalink to “一、市盈率（PE）”">​</a></h2><h3 id="公式" tabindex="-1">公式 <a class="header-anchor" href="#公式" aria-label="Permalink to “公式”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PE = 股价 ÷ 每股收益（EPS）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="人话版" tabindex="-1">人话版 <a class="header-anchor" href="#人话版" aria-label="Permalink to “人话版”">​</a></h3><p><strong>&quot;多少年回本&quot;</strong>。PE=30，就是以现在的利润算，需要30年才能赚回本金。</p><h3 id="生活比喻" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻" aria-label="Permalink to “生活比喻”">​</a></h3><p>你买了一套房子，每年收租2万，房价100万：</p><ul><li>回本年限 = 100 ÷ 2 = <strong>50年</strong></li><li>PE = 50</li></ul><p>这意味着你的租金回报率只有2%（1/50）。</p><h3 id="a股pe参考" tabindex="-1">A股PE参考 <a class="header-anchor" href="#a股pe参考" aria-label="Permalink to “A股PE参考”">​</a></h3><table tabindex="0"><thead><tr><th>行业</th><th>合理PE范围</th><th>原因</th></tr></thead><tbody><tr><td>银行</td><td>5-8倍</td><td>业绩稳定，但没有成长性</td></tr><tr><td>消费</td><td>20-35倍</td><td>品牌溢价，业绩稳定</td></tr><tr><td>医药</td><td>30-50倍</td><td>刚需+成长性</td></tr><tr><td>科技</td><td>50倍+</td><td>预期未来高速增长</td></tr><tr><td>钢铁/煤炭</td><td>5-10倍</td><td>强周期，盈利不稳定</td></tr></tbody></table><blockquote><p>⚠️ <strong>PE不能跨行业比较</strong>：银行业PE低不代表便宜，科技PE高不代表贵，因为行业特性完全不同。</p></blockquote><h3 id="pe的使用陷阱" tabindex="-1">PE的使用陷阱 <a class="header-anchor" href="#pe的使用陷阱" aria-label="Permalink to “PE的使用陷阱”">​</a></h3><table tabindex="0"><thead><tr><th>陷阱</th><th>说明</th></tr></thead><tbody><tr><td>低PE陷阱</td><td>低PE可能是因为公司要走下坡路了</td></tr><tr><td>高PE陷阱</td><td>高PE可能是市场预期太高，业绩不及就暴跌</td></tr><tr><td>负PE</td><td>公司亏损时PE无效</td></tr></tbody></table><h2 id="二、市净率-pb" tabindex="-1">二、市净率（PB） <a class="header-anchor" href="#二、市净率-pb" aria-label="Permalink to “二、市净率（PB）”">​</a></h2><h3 id="公式-1" tabindex="-1">公式 <a class="header-anchor" href="#公式-1" aria-label="Permalink to “公式”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PB = 股价 ÷ 每股净资产</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="人话版-1" tabindex="-1">人话版 <a class="header-anchor" href="#人话版-1" aria-label="Permalink to “人话版”">​</a></h3><p><strong>&quot;每股净资产是股价的多少倍&quot;</strong>。PB=3，就是股价是每股净资产的3倍。</p><h3 id="什么情况下pb更重要" tabindex="-1">什么情况下PB更重要？ <a class="header-anchor" href="#什么情况下pb更重要" aria-label="Permalink to “什么情况下PB更重要？”">​</a></h3><p>当PE失效时（公司亏损），用PB判断：</p><table tabindex="0"><thead><tr><th>情况</th><th>用什么估值</th></tr></thead><tbody><tr><td>盈利稳定</td><td>PE为主</td></tr><tr><td>公司亏损</td><td>PB为主</td></tr><tr><td>金融类（银行/保险）</td><td>PB更准确</td></tr><tr><td>轻资产公司（互联网）</td><td>PB参考价值低</td></tr></tbody></table><blockquote><p>💡 <strong>银行股用PB</strong>：每股净资产稳定，PB&lt;1意味着股价跌破净资产，理论上&quot;便宜&quot;。</p></blockquote><h2 id="三、股息率" tabindex="-1">三、股息率 <a class="header-anchor" href="#三、股息率" aria-label="Permalink to “三、股息率”">​</a></h2><h3 id="公式-2" tabindex="-1">公式 <a class="header-anchor" href="#公式-2" aria-label="Permalink to “公式”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>股息率 = 年度每股分红 ÷ 当前股价 × 100%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="人话版-2" tabindex="-1">人话版 <a class="header-anchor" href="#人话版-2" aria-label="Permalink to “人话版”">​</a></h3><p><strong>&quot;收租回报率&quot;</strong>。你买了一只股票，每年分红能拿多少回报。</p><h3 id="a股高股息率股票" tabindex="-1">A股高股息率股票 <a class="header-anchor" href="#a股高股息率股票" aria-label="Permalink to “A股高股息率股票”">​</a></h3><table tabindex="0"><thead><tr><th>股票</th><th>股息率</th><th>特点</th></tr></thead><tbody><tr><td>工商银行</td><td>~5%</td><td>国有大行，稳定</td></tr><tr><td>建设银行</td><td>~5%</td><td>国有大行，稳定</td></tr><tr><td>长江电力</td><td>~4%</td><td>水电，稳定</td></tr><tr><td>中国神华</td><td>~8%</td><td>煤炭周期股</td></tr></tbody></table><h3 id="股息率的意义" tabindex="-1">股息率的意义 <a class="header-anchor" href="#股息率的意义" aria-label="Permalink to “股息率的意义”">​</a></h3><ul><li>股息率高的股票适合<strong>不想炒短线、追求稳定现金流</strong>的投资者</li><li>被称为&quot;收息股&quot;或&quot;价值股&quot;</li></ul><h2 id="四、roe-净资产收益率" tabindex="-1">四、ROE（净资产收益率） <a class="header-anchor" href="#四、roe-净资产收益率" aria-label="Permalink to “四、ROE（净资产收益率）”">​</a></h2><h3 id="公式-3" tabindex="-1">公式 <a class="header-anchor" href="#公式-3" aria-label="Permalink to “公式”">​</a></h3><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ROE = 净利润 ÷ 净资产 × 100%</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="人话版-3" tabindex="-1">人话版 <a class="header-anchor" href="#人话版-3" aria-label="Permalink to “人话版”">​</a></h3><p><strong>&quot;公司用股东的钱，创造了多少回报&quot;</strong>。</p><h3 id="判断标准" tabindex="-1">判断标准 <a class="header-anchor" href="#判断标准" aria-label="Permalink to “判断标准”">​</a></h3><table tabindex="0"><thead><tr><th>ROE</th><th>评价</th></tr></thead><tbody><tr><td>&gt;20%</td><td>非常优秀</td></tr><tr><td>15%-20%</td><td>优秀</td></tr><tr><td>10%-15%</td><td>良好</td></tr><tr><td>&lt;10%</td><td>一般</td></tr></tbody></table><blockquote><p>💡 <strong>巴菲特最爱ROE</strong>：他选股的重要标准就是ROE长期&gt;15%。</p></blockquote><h2 id="五、估值总结表" tabindex="-1">五、估值总结表 <a class="header-anchor" href="#五、估值总结表" aria-label="Permalink to “五、估值总结表”">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>公式</th><th>用途</th><th>适用场景</th></tr></thead><tbody><tr><td>PE</td><td>股价/EPS</td><td>判断贵不贵</td><td>盈利稳定的公司</td></tr><tr><td>PB</td><td>股价/每股净资产</td><td>判断贵不贵</td><td>亏损/金融类公司</td></tr><tr><td>股息率</td><td>分红/股价</td><td>衡量现金回报</td><td>追求分红的投资者</td></tr><tr><td>ROE</td><td>净利润/净资产</td><td>衡量盈利能力</td><td>选好公司</td></tr></tbody></table><h2 id="六、如何综合判断估值" tabindex="-1">六、如何综合判断估值？ <a class="header-anchor" href="#六、如何综合判断估值" aria-label="Permalink to “六、如何综合判断估值？”">​</a></h2><blockquote><p>好公司 + 好价格 = 值得买入</p></blockquote><p><strong>好公司</strong>：ROE&gt;15%，业绩稳定增长 <strong>好价格</strong>：PE在历史低位，或低于行业平均</p><p><strong>举例</strong>：</p><ul><li>茅台是好公司，但PE长期在30-50倍，不便宜</li><li>工商银行估值低（PE=5），但成长性差</li></ul><p><strong>所以</strong>：好公司买贵了也可能亏损，差公司买便宜了也可能赚钱。</p><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某只股票PE=5（很低），另一只PE=50（很高）。你会选哪只？为什么？</p></blockquote><hr><p><strong>下一课预告</strong>：估值会看了，下一课学习<strong>K线基础</strong>——技术分析的入门工具。</p>',54)])])}const u=a(i,[["render",s]]);export{p as __pageData,u as default};
